MANAGEMENT_INVITE_ROLES: dict[str, dict[str, object]] = {
    "organization_lead": {"name": "组织负责人", "prefix": "OF", "order": 1},
    "advisor": {"name": "顾问", "prefix": "GW", "order": 2},
}


def _department_invite_checksum(organization_id: str, department_id: str) -> str:
    return _base36_seed(f"{organization_id}:{department_id}", 36 ** 4).zfill(4)[:4]


def _management_invite_checksum(organization_id: str, role_key: str) -> str:
    return _base36_seed(f"{organization_id}:management:{role_key}", 36 ** 4).zfill(4)[:4]


def _management_title_invite_checksum(organization_id: str, title_id: str) -> str:
    return _base36_seed(f"{organization_id}:management:{title_id}", 36 ** 4).zfill(4)[:4]


def _department_invite_code(
    department_id: str,
    *,
    organization_id: str = "",
    organization_name: str = "",
    department_name: str = "",
    order: int | None = None,
) -> str:
    if not organization_id and not organization_name and not department_name and not isinstance(order, int):
        return _invite_seed(department_id)
    org_prefix = _normalize_invite_segment(organization_name, 4) or _base36_seed(organization_id, 36 ** 4).zfill(4)[:4] or "ORGX"
    dept_prefix = _normalize_invite_segment(department_name, 2) or _base36_seed(department_id, 36 ** 2).zfill(2)[:2] or "BM"
    if isinstance(order, int):
        order_value = max(1, order + 1)
    else:
        order_value = (int(_invite_seed(department_id)[-2:]) % 99) + 1
    checksum = _department_invite_checksum(organization_id, department_id)
    return f"{org_prefix}-{dept_prefix}{str(order_value).zfill(2)}-{checksum}"


def _management_invite_code(
    organization_id: str,
    role_key: str,
    *,
    organization_name: str = "",
) -> str:
    meta = MANAGEMENT_INVITE_ROLES.get(role_key) or MANAGEMENT_INVITE_ROLES["advisor"]
    org_prefix = _normalize_invite_segment(organization_name, 4) or _base36_seed(organization_id, 36 ** 4).zfill(4)[:4] or "ORGX"
    role_prefix = str(meta["prefix"])
    order_value = int(meta["order"])
    checksum = _management_invite_checksum(organization_id, role_key)
    return f"{org_prefix}-{role_prefix}{str(order_value).zfill(2)}-{checksum}"


def _management_title_invite_code(
    organization_id: str,
    title_id: str,
    *,
    organization_name: str = "",
    title_name: str = "",
    order: int | None = None,
) -> str:
    org_prefix = _normalize_invite_segment(organization_name, 4) or _base36_seed(organization_id, 36 ** 4).zfill(4)[:4] or "ORGX"
    title_prefix = _normalize_invite_segment(title_name, 2) or _base36_seed(title_id, 36 ** 2).zfill(2)[:2] or "GL"
    if isinstance(order, int):
        order_value = max(1, order + 1)
    else:
        order_value = (int(_invite_seed(title_id)[-2:]) % 99) + 1
    checksum = _management_title_invite_checksum(organization_id, title_id)
    return f"{org_prefix}-{title_prefix}{str(order_value).zfill(2)}-{checksum}"


def _department_invite_lookup_values(raw_code: str | None) -> list[str]:
    value = (raw_code or "").strip()
    if not value:
        return []
    candidates: list[str] = []

    def add(candidate: str | None) -> None:
        item = (candidate or "").strip()
        if not item:
            return
        try:
            item = unquote(item).strip()
        except Exception:
            pass
        if item and item not in candidates:
            candidates.append(item)

    add(value)
    try:
        parsed_url = urlparse(value)
        for key in ("invite", "code", "inviteCode", "departmentId"):
            for item in parse_qs(parsed_url.query).get(key, []):
                add(item)
    except Exception:
        pass
    for pattern in (
        r"invite=([^&\s]+)",
        r"code=([^&\s]+)",
        r"inviteCode=([^&\s]+)",
        r"departmentId=([^&\s]+)",
    ):
        for match in re.finditer(pattern, value, re.IGNORECASE):
            add(match.group(1))
    formatted = re.search(r"\b([A-Z0-9]{2,8}-[A-Z0-9]{2,8}(?:-[A-Z0-9]{2,8})?)\b", value, re.IGNORECASE)
    if formatted:
        add(formatted.group(1).upper())
    legacy_numeric = re.search(r"\b(\d{6})\b", value)
    if legacy_numeric:
        add(legacy_numeric.group(1))
    legacy_department_id = re.search(r"\b(dept_[A-Za-z0-9_]+)\b", value)
    if legacy_department_id:
        add(legacy_department_id.group(1))
    return candidates


def _resolved_invite_from_department_row(row) -> ResolvedDepartmentInvite:
    return ResolvedDepartmentInvite(
        organization_id=str(row["organization_id"]),
        organization_name=str(_row_get(row, "organization_name") or ""),
        department_id=str(row["id"]),
        department_name=str(row["name"]),
        color=str(row["color"] or "#5B7BFE"),
    )


def _resolved_invite_from_management_role(
    organization_id: str,
    organization_name: str,
    role_key: str,
    *,
    role_id: str | None = None,
    role_name: str | None = None,
) -> ResolvedManagementInvite:
    meta = MANAGEMENT_INVITE_ROLES.get(role_key) or MANAGEMENT_INVITE_ROLES["advisor"]
    return ResolvedManagementInvite(
        organization_id=organization_id,
        organization_name=organization_name,
        role_id=role_id,
        role_key=role_key,
        role_name=str(role_name or meta["name"]),
    )


def _department_option_from_row(row) -> DepartmentOption:
    return DepartmentOption(id=str(row["id"]), name=str(row["name"]), color=str(row["color"] or "#5B7BFE"))


def _list_department_option_rows(state: AppState, organization_id: str):
    return state.db.fetchall(
        """
        SELECT id, name, color
        FROM org_departments
        WHERE organization_id = ? AND COALESCE(active, 1) != 0
        ORDER BY name COLLATE NOCASE ASC
        """,
        (organization_id,),
    )


def _get_org_department_option(state: AppState, organization_id: str, department_id: str | None) -> DepartmentOption | None:
    if not department_id:
        return None
    row = state.db.fetchone(
        """
        SELECT id, name, color
        FROM org_departments
        WHERE organization_id = ? AND id = ? AND COALESCE(active, 1) != 0
        """,
        (organization_id, department_id),
    )
    return _department_option_from_row(row) if row else None


def _resolve_department_id_globally(
    state: AppState,
    department_id: str | None,
    *,
    organization_id: str | None = None,
) -> ResolvedDepartmentInvite | None:
    value = (department_id or "").strip()
    if not value:
        return None
    params: list[str] = []
    query = """
        SELECT departments.id, departments.organization_id, departments.name, departments.color, organizations.name AS organization_name
        FROM org_departments AS departments
        JOIN organizations ON organizations.id = departments.organization_id
        WHERE departments.id = ? AND COALESCE(departments.active, 1) != 0
    """
    params.append(value)
    if organization_id:
        query += " AND departments.organization_id = ?"
        params.append(organization_id)
    row = state.db.fetchone(query, tuple(params))
    return _resolved_invite_from_department_row(row) if row else None


def _resolve_department_from_invite(
    state: AppState,
    raw_code: str | None,
    *,
    organization_id: str | None = None,
    strict: bool = False,
) -> ResolvedDepartmentInvite | None:
    lookup_values = _department_invite_lookup_values(raw_code)
    if not lookup_values:
        return None
    if strict:
        # 封测安全(P0-1): 注册 / 跨组加入这类"授予某组成员身份→可读该组数据"的路径,
        # 只接受带校验和的完整邀请码(ORG-DEPT##-CHECKSUM, 校验和由 org_id:dept_id 派生),
        # 拒绝按部门名(如"战略部")/裸部门ID 的弱匹配 —— 防止外部隔离-org 账号靠猜
        # inviteCode 把自己塞进他组。身份解析类端点(department-options / invite-code/resolve)
        # 不传 strict, 行为不变。
        strict_rows = state.db.fetchall(
            """
            SELECT departments.id, departments.organization_id, departments.name, departments.color,
                   organizations.name AS organization_name
            FROM org_departments AS departments
            JOIN organizations ON organizations.id = departments.organization_id
            WHERE COALESCE(departments.active, 1) != 0
            """,
        )
        for value in lookup_values:
            formatted_match = re.match(r"^([A-Z0-9]{2,8})-([A-Z0-9]{2,8})-([A-Z0-9]{2,8})$", value.upper())
            if not formatted_match:
                continue
            supplied_checksum = formatted_match.group(3)
            for row in strict_rows:
                if supplied_checksum == _department_invite_checksum(str(row["organization_id"]), str(row["id"])):
                    return _resolved_invite_from_department_row(row)
        return None
    for value in lookup_values:
        normalized = value.upper()
        if normalized.startswith("DEPT:"):
            resolved = _resolve_department_id_globally(state, value[5:].strip(), organization_id=organization_id)
            if resolved:
                return resolved
        if "DEPARTMENTID=" in normalized:
            match = re.search(r"departmentId=([^&\s]+)", value, re.IGNORECASE)
            if match:
                resolved = _resolve_department_id_globally(state, match.group(1).strip(), organization_id=organization_id)
                if resolved:
                    return resolved
        if re.fullmatch(r"dept_[A-Za-z0-9_]+", value):
            resolved = _resolve_department_id_globally(state, value, organization_id=organization_id)
            if resolved:
                return resolved
    for value in lookup_values:
        match = re.search(r"departmentId=([^&\s]+)", value, re.IGNORECASE)
        if match:
            resolved = _resolve_department_id_globally(state, match.group(1).strip(), organization_id=organization_id)
            if resolved:
                return resolved

    params: list[str] = []
    query = """
        SELECT departments.id, departments.organization_id, departments.name, departments.color, organizations.name AS organization_name
        FROM org_departments AS departments
        JOIN organizations ON organizations.id = departments.organization_id
        WHERE COALESCE(departments.active, 1) != 0
    """
    if organization_id:
        query += " AND departments.organization_id = ?"
        params.append(organization_id)
    query += " ORDER BY departments.organization_id ASC, departments.name COLLATE NOCASE ASC"
    rows = state.db.fetchall(query, tuple(params))
    for value in lookup_values:
        normalized = value.upper()
        formatted_match = re.match(r"^([A-Z0-9]{2,8})-([A-Z0-9]{2,8})(?:-([A-Z0-9]{2,8}))?$", normalized)
        for index, row in enumerate(rows):
            department_id = str(row["id"])
            department_name = str(row["name"])
            department_org_id = str(row["organization_id"])
            organization_name = str(row["organization_name"])
            checksum = _department_invite_checksum(department_org_id, department_id)
            if formatted_match and formatted_match.group(3) and formatted_match.group(3) == checksum:
                return _resolved_invite_from_department_row(row)
            if normalized in {
                _department_invite_code(
                    department_id,
                    organization_id=department_org_id,
                    organization_name=organization_name,
                    department_name=department_name,
                    order=index,
                ),
                f"{_normalize_invite_segment(organization_name, 4) or _base36_seed(department_org_id, 36 ** 4).zfill(4)[:4]}-"
                f"{_normalize_invite_segment(department_name, 2) or _base36_seed(department_id, 36 ** 2).zfill(2)[:2]}"
                f"{str(max(1, index + 1)).zfill(2)}",
                _invite_seed(department_id),
                department_id.upper(),
                department_name.upper(),
            }:
                return _resolved_invite_from_department_row(row)
    return None


def _list_management_title_rows(state: AppState, organization_id: str):
    return state.db.fetchall(
        """
        SELECT *
        FROM org_role_templates
        WHERE organization_id = ?
          AND department_id IS NULL
          AND COALESCE(active, 1) != 0
          AND (
            COALESCE(visibility_scope, '') = 'organization'
            OR COALESCE(task_edit_scope, '') = 'organization'
            OR COALESCE(is_manager, 0) != 0
            OR COALESCE(level, '') = 'organization_lead'
          )
        ORDER BY sort_order ASC, updated_at DESC, name COLLATE NOCASE ASC
        """,
        (organization_id,),
    )


def _resolve_management_from_invite(
    state: AppState,
    raw_code: str | None,
    *,
    organization_id: str | None = None,
    strict: bool = False,
) -> ResolvedManagementInvite | None:
    lookup_values = _department_invite_lookup_values(raw_code)
    if not lookup_values:
        return None
    params: list[str] = []
    query = "SELECT id, name FROM organizations"
    if organization_id:
        query += " WHERE id = ?"
        params.append(organization_id)
    query += " ORDER BY created_at ASC"
    rows = state.db.fetchall(query, tuple(params))
    for value in lookup_values:
        normalized = value.upper()
        formatted_match = re.match(r"^([A-Z0-9]{2,8})-([A-Z0-9]{2,8})-([A-Z0-9]{2,8})$", normalized)
        if strict and not formatted_match:
            continue
        for row in rows:
            org_id = str(row["id"])
            org_name = str(row["name"] or "")
            for index, title_row in enumerate(_list_management_title_rows(state, org_id)):
                title_id = str(title_row["id"])
                title_name = str(title_row["name"] or "")
                checksum = _management_title_invite_checksum(org_id, title_id)
                expected = _management_title_invite_code(
                    org_id,
                    title_id,
                    organization_name=org_name,
                    title_name=title_name,
                    order=index,
                )
                if formatted_match:
                    supplied_checksum = formatted_match.group(3)
                    if supplied_checksum == checksum:
                        return _resolved_invite_from_management_role(
                            org_id,
                            org_name,
                            title_id,
                            role_id=title_id,
                            role_name=title_name,
                        )
                elif not strict and normalized in {expected, title_id.upper(), title_name.upper()}:
                    return _resolved_invite_from_management_role(
                        org_id,
                        org_name,
                        title_id,
                        role_id=title_id,
                        role_name=title_name,
                    )
            for role_key, meta in MANAGEMENT_INVITE_ROLES.items():
                checksum = _management_invite_checksum(org_id, role_key)
                expected = _management_invite_code(org_id, role_key, organization_name=org_name)
                role_segment = f"{str(meta['prefix']).upper()}{str(int(meta['order'])).zfill(2)}"
                if formatted_match:
                    supplied_role_segment = formatted_match.group(2)
                    supplied_checksum = formatted_match.group(3)
                    if supplied_role_segment == role_segment and supplied_checksum == checksum:
                        return _resolved_invite_from_management_role(org_id, org_name, role_key)
                elif not strict and normalized == expected:
                    return _resolved_invite_from_management_role(org_id, org_name, role_key)
    return None


def _resolve_org_invite(
    state: AppState,
    raw_code: str | None,
    *,
    organization_id: str | None = None,
    strict: bool = False,
) -> ResolvedOrgInvite | None:
    department = _resolve_department_from_invite(state, raw_code, organization_id=organization_id, strict=strict)
    if department:
        return ResolvedOrgInvite(
            organization_id=department.organization_id,
            organization_name=department.organization_name,
            target_type="department",
            department=department,
        )
    management = _resolve_management_from_invite(state, raw_code, organization_id=organization_id, strict=strict)
    if management:
        return ResolvedOrgInvite(
            organization_id=management.organization_id,
            organization_name=management.organization_name,
            target_type="management_role",
            management=management,
        )
    return None


def _ensure_management_role_template(state: AppState, organization_id: str, role_key: str, timestamp: str) -> str:
    meta = MANAGEMENT_INVITE_ROLES.get(role_key) or MANAGEMENT_INVITE_ROLES["advisor"]
    role_name = str(meta["name"])
    row = state.db.fetchone(
        """
        SELECT id
        FROM org_role_templates
        WHERE organization_id = ?
          AND department_id IS NULL
          AND name = ?
          AND active = 1
        ORDER BY updated_at DESC
        LIMIT 1
        """,
        (organization_id, role_name),
    )
    if row:
        return str(row["id"])
    role_id = f"role_{_base36_seed(organization_id, 36 ** 6).lower()}_{role_key}"
    existing = state.db.fetchone("SELECT id FROM org_role_templates WHERE id = ?", (role_id,))
    if existing:
        role_id = new_id("role")
    level = "organization_lead"
    state.db.execute(
        """
        INSERT INTO org_role_templates(
            id, organization_id, department_id, name, level, manager_role_id, is_manager, goal,
            responsibilities_json, should_avoid_json, collaboration_role_ids_json, task_edit_scope,
            can_approve_tasks, can_reassign_tasks, can_change_deadline, holder_bot_id, sort_order, active, updated_at,
            visibility_scope
        ) VALUES(?, ?, NULL, ?, ?, NULL, 1, '', '[]', '[]', '[]', 'organization', 1, 1, 1, NULL, ?, 1, ?, 'organization')
        """,
        (role_id, organization_id, role_name, level, int(meta["order"]), timestamp),
    )
    return role_id


def _assign_management_role_to_employee(
    state: AppState,
    organization_id: str,
    employee_id: str,
    role_key: str,
    timestamp: str,
    role_id: str | None = None,
    role_name: str | None = None,
) -> None:
    role_id = role_id or _ensure_management_role_template(state, organization_id, role_key, timestamp)
    if role_name is None:
        role_row = _org_role_row(state, organization_id, role_id)
        role_name = str(role_row["name"] or "") if role_row else ""
    state.db.execute(
        """
        INSERT OR REPLACE INTO org_employee_role_bindings(
            user_id, organization_id, department_id, primary_role_id, manager_user_id, is_manager,
            project_role_labels_json, current_focus, task_edit_scope, can_approve_tasks,
            can_reassign_tasks, can_change_deadline, updated_at, visibility_scope
        ) VALUES(?, ?, NULL, ?, NULL, 1, '[]', '', 'organization', 1, 1, 1, ?, 'organization')
        """,
        (employee_id, organization_id, role_id, timestamp),
    )
    state.db.execute(
        """
        UPDATE employee_accounts
           SET visibility_scope = 'organization',
               management_title_id = ?,
               management_title_name = ?,
               job_title = COALESCE(NULLIF(?, ''), job_title),
               is_department_lead = 0,
               updated_at = ?
         WHERE id = ? AND organization_id = ?
        """,
        (role_id, role_name or None, role_name or "", timestamp, employee_id, organization_id),
    )


def _create_registration_organization(
    state: AppState,
    full_name: str,
    timestamp: str,
    organization_name: str | None = None,
) -> tuple[str, str]:
    organization_id = new_id("org")
    explicit_organization_name = (organization_name or "").strip()
    owner_name = (full_name or "").strip()
    display_name = explicit_organization_name or (f"{owner_name} 的组织" if owner_name else "未命名组织")
    slug = f"org-{_base36_seed(organization_id, 36 ** 8).lower()}"
    state.db.execute(
        "INSERT INTO organizations(id, name, slug, created_at, updated_at) VALUES(?, ?, ?, ?, ?)",
        (organization_id, display_name, slug, timestamp, timestamp),
    )
    state.db.execute(
        """
        INSERT INTO org_profiles(
            organization_id, annual_goal, annual_strategy_year, annual_strategy_text, quarter_plans_json,
            quarterly_focus_json, leader_user_id, leader_name, management_user_ids_json, updated_at
        ) VALUES(?, '', ?, '', '[]', '[]', NULL, '', '[]', ?)
        """,
        (organization_id, str(datetime.now().year), timestamp),
    )
    _ensure_org_default_task_list(state, organization_id)
    return organization_id, display_name


def _ensure_org_default_task_list(state: AppState, organization_id: str):
    """Ensure every organization has its own cloud-side inbox list.

    `task_lists.id` is globally unique, so only the legacy default organization
    may use `list-0`; newly created organizations receive their own list id.
    """
    normalized_org_id = str(organization_id or "").strip()
    if not normalized_org_id:
        return None
    state.db.execute(
        "UPDATE task_lists SET scope = 'org' WHERE organization_id = ? AND (scope IS NULL OR scope = '')",
        (normalized_org_id,),
    )
    inbox_row = _find_active_task_list_by_name(state, normalized_org_id, "org", "收集箱")
    if inbox_row is None:
        preferred_id = "list-0" if normalized_org_id == DEFAULT_ORG_ID else new_id("list")
        if state.db.fetchone("SELECT id FROM task_lists WHERE id = ?", (preferred_id,)):
            preferred_id = new_id("list")
        state.db.execute(
            """
            INSERT INTO task_lists(id, organization_id, name, color, sort_order, is_default, scope, archived_at)
            VALUES(?, ?, '收集箱', '#5B7BFE', 0, 1, 'org', NULL)
            """,
            (preferred_id, normalized_org_id),
        )
        inbox_row = state.db.fetchone(
            "SELECT * FROM task_lists WHERE id = ? AND organization_id = ?",
            (preferred_id, normalized_org_id),
        )
    if _task_settings_default_destination_row(state, normalized_org_id) is None and inbox_row is not None:
        state.db.execute(
            "UPDATE task_lists SET is_default = CASE WHEN id = ? THEN 1 ELSE 0 END WHERE organization_id = ? AND scope = 'org'",
            (str(inbox_row["id"]), normalized_org_id),
        )
    return inbox_row


def _resolve_task_list_or_org_default(state: AppState, organization_id: str, list_id: str | None):
    normalized_list_id = str(list_id or "").strip()
    row = state.db.fetchone(
        "SELECT * FROM task_lists WHERE id = ? AND organization_id = ?",
        (normalized_list_id, organization_id),
    ) if normalized_list_id else None
    if row and not row["archived_at"]:
        return row
    row = _ensure_org_default_task_list(state, organization_id)
    if row and not row["archived_at"]:
        return row
    raise HTTPException(status_code=400, detail="组织云任务清单未初始化，请刷新任务清单后重试")


_ORG_NAME_CACHE: dict[str, str] = {}


def _organization_name(state: AppState, organization_id: str) -> str | None:
    """读取组织名 + 进程级缓存。手机端在登录后需要立即显示企业身份，这是
    手机端唯一会"自动出现"的组织信息，必须保证 SessionUser 出口都带上。"""
    if not organization_id:
        return None
    cached = _ORG_NAME_CACHE.get(organization_id)
    if cached is not None:
        return cached or None
    row = state.db.fetchone("SELECT name FROM organizations WHERE id = ?", (organization_id,))
    name = str(row["name"]).strip() if row and row["name"] else ""
    _ORG_NAME_CACHE[organization_id] = name
    return name or None


def _member_visibility_scope_from_row(row) -> str:
    if str(_row_get(row, "primary_role") or "") == "admin":
        return "organization"
    raw_scope = str(_row_get(row, "visibility_scope") or "").strip()
    if raw_scope in {"organization", "department", "self"}:
        return raw_scope
    if bool(int(_row_get(row, "is_department_lead") or 0)):
        return "department"
    return "self"


def _member_management_title_id_from_row(row) -> str | None:
    value = str(_row_get(row, "management_title_id") or "").strip()
    return value or None


def _member_management_title_name_from_row(row) -> str | None:
    value = str(_row_get(row, "management_title_name") or "").strip()
    if value:
        return value
    if _member_visibility_scope_from_row(row) == "organization" and str(_row_get(row, "primary_role") or "") != "admin":
        fallback = str(_row_get(row, "job_title") or "").strip()
        return fallback or None
    return None


def _row_user(state: AppState, row) -> SessionUser:
    department_id = str(_row_get(row, "department_id") or "") or None
    department_name = str(_row_get(row, "department_name") or "") or None
    organization_id = str(row["organization_id"])
    organization_name = _organization_name(state, organization_id)
    avatar_url = str(_row_get(row, "avatar_url") or "") or None
    identity = _identity_row_for_member(state, row)
    return SessionUser(
        id=str(row["id"]),
        organizationId=organization_id,
        organizationName=organization_name,
        email=str(identity["email"] if identity else row["email"]),
        phone=str((identity["phone_number"] if identity else _row_get(row, "phone_number")) or "") or None,
        fullName=str(row["full_name"]),
        primaryRole=str(row["primary_role"]),
        accountStatus=str(row["account_status"]),
        membershipStatus=_account_membership_status(row),
        membershipRejectedReason=str(_row_get(row, "membership_rejected_reason") or _row_get(row, "rejected_reason") or "") or None,
        departmentId=department_id,
        departmentName=department_name,
        avatarUrl=avatar_url,
        isDepartmentLead=bool(int(row["is_department_lead"] or 0)) if "is_department_lead" in row.keys() else False,
        visibilityScope=_member_visibility_scope_from_row(row),
        managementTitleId=_member_management_title_id_from_row(row),
        managementTitleName=_member_management_title_name_from_row(row),
    )


def _employee_record(row) -> EmployeeRecord:
    department_id = str(_row_get(row, "department_id") or "") or None
    department_name = str(_row_get(row, "department_name") or "") or None
    return EmployeeRecord(
        id=str(row["id"]),
        email=str(row["email"]),
        phone=str(_row_get(row, "phone_number") or "") or None,
        fullName=str(row["full_name"]),
        primaryRole=str(row["primary_role"]),
        accountStatus=str(row["account_status"]),
        membershipStatus=_account_membership_status(row),
        membershipRejectedReason=str(_row_get(row, "membership_rejected_reason") or row["rejected_reason"] or "") or None,
        membershipSubmittedAt=str(_row_get(row, "membership_submitted_at") or "") or None,
        departmentId=department_id,
        departmentName=department_name,
        jobTitle=str(row["job_title"]) if row["job_title"] else None,
        managerName=str(row["manager_name"]) if row["manager_name"] else None,
        currentFocus=str(row["current_focus"]) if row["current_focus"] else None,
        isDepartmentLead=bool(int(row["is_department_lead"] or 0)),
        visibilityScope=_member_visibility_scope_from_row(row),
        managementTitleId=_member_management_title_id_from_row(row),
        managementTitleName=_member_management_title_name_from_row(row),
        approvedAt=row["approved_at"],
        rejectedReason=row["rejected_reason"],
        disabledAt=row["disabled_at"],
        lastLoginAt=row["last_login_at"],
        createdAt=str(row["created_at"]),
    )


def _identity_row_for_member(state: AppState, member_row):
    identity_id = str(_row_get(member_row, "identity_id") or "").strip()
    if not identity_id:
        return None
    return state.db.fetchone("SELECT * FROM cloud_identities WHERE id = ?", (identity_id,))


def _identity_row_by_identifier(state: AppState, identifier: str):
    value = str(identifier or "").strip()
    if not value:
        return None
    if "@" in value:
        identity = state.db.fetchone("SELECT * FROM cloud_identities WHERE email = ?", (value.lower(),))
        if identity:
            return identity
        legacy = state.db.fetchone("SELECT * FROM employee_accounts WHERE email = ? ORDER BY created_at ASC LIMIT 1", (value.lower(),))
        return _ensure_identity_from_legacy_member(state, legacy) if legacy else None
    normalized_phone = _normalize_account_phone(value)
    if normalized_phone:
        identity = state.db.fetchone("SELECT * FROM cloud_identities WHERE phone_number = ?", (normalized_phone,))
        if identity:
            return identity
        legacy = state.db.fetchone("SELECT * FROM employee_accounts WHERE phone_number = ? ORDER BY created_at ASC LIMIT 1", (normalized_phone,))
        return _ensure_identity_from_legacy_member(state, legacy) if legacy else None
    return None


def _identity_row_by_email(state: AppState, email: str):
    normalized_email = str(email or "").strip().lower()
    identity = state.db.fetchone("SELECT * FROM cloud_identities WHERE email = ?", (normalized_email,))
    if identity:
        return identity
    legacy = state.db.fetchone("SELECT * FROM employee_accounts WHERE email = ? ORDER BY created_at ASC LIMIT 1", (normalized_email,))
    return _ensure_identity_from_legacy_member(state, legacy) if legacy else None


def _ensure_identity_from_legacy_member(state: AppState, member_row):
    if not member_row:
        return None
    existing = _identity_row_for_member(state, member_row)
    if existing:
        return existing
    timestamp = now_iso()
    email = str(member_row["email"] or "").strip().lower()
    if not email:
        return None
    identity_id = new_id("ident")
    phone = str(_row_get(member_row, "phone_number") or "").strip() or None
    if phone:
        phone_owner = state.db.fetchone("SELECT id FROM cloud_identities WHERE phone_number = ?", (phone,))
        if phone_owner:
            phone = None
    state.db.execute(
        """
        INSERT INTO cloud_identities(id, email, phone_number, full_name, password_hash, last_login_at, created_at, updated_at)
        VALUES(?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            identity_id,
            email,
            phone,
            str(member_row["full_name"] or ""),
            str(member_row["password_hash"] or ""),
            _row_get(member_row, "last_login_at"),
            _row_get(member_row, "created_at") or timestamp,
            timestamp,
        ),
    )
    state.db.execute("UPDATE employee_accounts SET identity_id = ? WHERE email = ?", (identity_id, email))
    return state.db.fetchone("SELECT * FROM cloud_identities WHERE id = ?", (identity_id,))


def _member_rows_for_identity(state: AppState, identity_id: str) -> list:
    rows = state.db.fetchall(
        """
        SELECT ea.*, o.name AS organization_name, o.slug AS organization_slug
        FROM employee_accounts ea
        JOIN organizations o ON o.id = ea.organization_id
        WHERE ea.identity_id = ?
          AND ea.account_status != 'disabled'
        ORDER BY
          CASE COALESCE(ea.membership_status, ea.account_status)
            WHEN 'approved' THEN 0
            WHEN 'pending' THEN 1
            WHEN 'none' THEN 2
            ELSE 3
          END,
          ea.created_at ASC
        """,
        (identity_id,),
    )
    return [_repair_membership_status_from_account(state, row) for row in rows]


def _organization_candidate_from_member(state: AppState, row) -> OrganizationCandidate:
    department_id = str(_row_get(row, "department_id") or "") or None
    department_name = str(_row_get(row, "department_name") or "") or None
    identity = _identity_row_for_member(state, row)
    return OrganizationCandidate(
        organizationId=str(row["organization_id"]),
        organizationName=str(_row_get(row, "organization_name") or _organization_name(state, str(row["organization_id"])) or ""),
        organizationSlug=str(_row_get(row, "organization_slug") or "") or None,
        memberId=str(row["id"]),
        fullName=str(row["full_name"]),
        email=str(identity["email"] if identity else row["email"]),
        primaryRole=str(row["primary_role"]),
        accountStatus=str(row["account_status"]),
        membershipStatus=_account_membership_status(row),
        departmentId=department_id,
        departmentName=department_name,
    )


def _create_identity_for_credentials(
    state: AppState,
    *,
    email: str,
    phone: str | None,
    full_name: str,
    password_hash: str,
    timestamp: str,
):
    normalized_email = str(email or "").strip().lower()
    existing = _identity_row_by_email(state, normalized_email)
    if existing:
        return existing
    normalized_phone = _normalize_account_phone(phone)
    if normalized_phone:
        phone_owner = state.db.fetchone("SELECT id FROM cloud_identities WHERE phone_number = ?", (normalized_phone,))
        if phone_owner:
            raise HTTPException(status_code=409, detail="手机号已绑定其他账号")
    identity_id = new_id("ident")
    state.db.execute(
        """
        INSERT INTO cloud_identities(id, email, phone_number, full_name, password_hash, last_login_at, created_at, updated_at)
        VALUES(?, ?, ?, ?, ?, NULL, ?, ?)
        """,
        (identity_id, normalized_email, normalized_phone or None, full_name, password_hash, timestamp, timestamp),
    )
    row = state.db.fetchone("SELECT * FROM cloud_identities WHERE id = ?", (identity_id,))
    if not row:
        raise HTTPException(status_code=500, detail="身份创建失败")
    return row


# ───────────────────────── 机器人同事(bot)云端注册表 helpers ─────────────────────────
# 默认能力清单(对齐桌面 bot_permission_policies 的 6 项): (key, enabled, approval_required)
_DEFAULT_BOT_CAPABILITIES = [
    ("workspace_file_write.request", False, True),
    ("data_center_parse.request", True, True),
    ("external_material_draft.create", True, True),
    ("external_send.request", False, True),
    ("clarification_resolution.propose", False, True),
    ("inline_approval.allow_from_supervisor", True, False),
]


def _bot_hash_token(token: str, salt: str) -> str:
    """与桌面 bot_members._hash_bot_token 完全一致: hmac_sha256(salt, token).hexdigest()."""
    return hmac.new(salt.encode("utf-8"), token.encode("utf-8"), hashlib.sha256).hexdigest()


def _bot_slug_handle(name: str) -> str:
    name = (name or "").strip()
    if not name:
        return f"bot_{uuid4().hex[:8]}"
    if re.search(r"[一-龥]", name):
        return name
    return re.sub(r"\s+", "_", name.lower())


def _bot_auto_actor_id(handle: str) -> str:
    if re.match(r"^[a-zA-Z0-9_]+$", handle):
        return f"bot_{handle.lower()}"
    return f"bot_{hashlib.md5(handle.encode('utf-8')).hexdigest()[:12]}"


def _default_bot_capabilities_json() -> str:
    return to_json([
        {"capabilityKey": k, "enabled": en, "approvalRequired": req, "approvalPolicy": "supervisor_required"}
        for (k, en, req) in _DEFAULT_BOT_CAPABILITIES
    ])


def _org_bot_record(row, *, token_plain: str | None = None) -> OrgBotRecord:
    reporting_raw = from_json(_row_get(row, "reporting_json") or "{}", {}) or {}
    caps_raw = from_json(_row_get(row, "capabilities_json") or "[]", []) or []
    reporting = OrgBotReportingRecord(
        reportToCreator=bool(reporting_raw.get("reportToCreator", True)),
        reportToDepartmentLead=bool(reporting_raw.get("reportToDepartmentLead", True)),
        reportToCeo=bool(reporting_raw.get("reportToCeo", True)),
        departmentLeaderUserIds=[str(x) for x in reporting_raw.get("departmentLeaderUserIds", []) if str(x)],
        ceoUserIds=[str(x) for x in reporting_raw.get("ceoUserIds", []) if str(x)],
        approvalMode=str(reporting_raw.get("approvalMode", "any_one")),
    )
    capabilities = [
        OrgBotCapabilityRecord(
            capabilityKey=str(c.get("capabilityKey") or c.get("capability_key") or ""),
            enabled=bool(c.get("enabled", False)),
            approvalRequired=bool(c.get("approvalRequired", c.get("approval_required", True))),
            approvalPolicy=str(c.get("approvalPolicy") or c.get("approval_policy") or "supervisor_required"),
        )
        for c in caps_raw
        if isinstance(c, dict) and (c.get("capabilityKey") or c.get("capability_key"))
    ]
    return OrgBotRecord(
        id=str(row["id"]),
        displayName=str(row["display_name"]),
        handle=str(row["handle"]),
        actorId=str(row["actor_id"]),
        actorType=str(_row_get(row, "actor_type") or "internal_ai_agent"),
        departmentId=str(_row_get(row, "department_id") or "") or None,
        departmentName=str(_row_get(row, "department_name") or ""),
        description=str(_row_get(row, "description") or ""),
        status=str(_row_get(row, "status") or "active"),
        createdByUserId=str(_row_get(row, "created_by_user_id") or "") or None,
        tokenPrefix=str(_row_get(row, "token_prefix") or ""),
        tokenRotatedAt=_row_get(row, "token_rotated_at"),
        hasToken=bool(_row_get(row, "token_hash")),
        reporting=reporting,
        capabilities=capabilities,
        createdAt=str(_row_get(row, "created_at") or ""),
        updatedAt=str(_row_get(row, "updated_at") or ""),
        tokenPlain=token_plain,
    )


