    @app.post("/api/v1/consultation/knowledge-requests/{request_id}/status", response_model=ConsultationKnowledgeRequestRecord)
    def update_consultation_knowledge_request(
        request_id: str,
        payload: ConsultationKnowledgeRequestUpdatePayload,
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> ConsultationKnowledgeRequestRecord:
        row = _consultation_request_row_or_404(state, request_id, current_user.organizationId)
        can_update = current_user.primaryRole == "admin" or str(row["requested_by_user_id"]) == current_user.id
        if not can_update:
            raise HTTPException(status_code=403, detail="你当前没有处理该沉淀请求的权限")

        timestamp = now_iso()
        normalized_error = payload.errorMessage.strip() or None
        completed_at = timestamp if payload.status == "completed" else None
        if payload.status == "processing":
            normalized_error = None
        state.db.execute(
            """
            UPDATE consultation_knowledge_requests
            SET status = ?, error_message = ?, local_document_id = ?, local_document_path = ?, completed_at = ?, updated_at = ?
            WHERE id = ?
            """,
            (
                payload.status,
                normalized_error,
                payload.localDocumentId,
                payload.localDocumentPath,
                completed_at,
                timestamp,
                request_id,
            ),
        )
        _log_audit(
            state,
            "consultation.knowledge_request_updated",
            actor_user_id=current_user.id,
            target_user_id=None,
            detail={
                "requestId": request_id,
                "status": payload.status,
                "localDocumentId": payload.localDocumentId or "",
                "localDocumentPath": payload.localDocumentPath or "",
            },
        )
        updated_row = _consultation_request_row_or_404(state, request_id, current_user.organizationId)
        return _consultation_knowledge_request_record(updated_row)

    # ── 链接转文字中继队列 (手机提交 → 桌面端处理) ────────────
    # 手机端在咨询页粘贴 B站/小红书 链接 → 此队列;桌面端复用 process-pending 轮询认领,
    # 灌进本地 link_material_import 管线(浏览器cookie/impersonate反爬只在桌面可用),
    # 结果(文档id/路径)回写。队列可见性=组织级(入库目标本就是组织数据中心)。

    def _link_import_request_record(row) -> LinkImportRequestRecord:
        return LinkImportRequestRecord(
            id=str(row["id"]),
            organizationId=str(row["organization_id"]),
            url=str(row["url"]),
            sourceHint=row["source_hint"],
            clientId=row["client_id"],
            clientName=row["client_name"],
            status=str(row["status"]),
            requestedByUserId=str(row["requested_by_user_id"]),
            requestedByName=str(row["requested_by_name"] or "") if "requested_by_name" in row.keys() else "",
            errorMessage=row["error_message"],
            localRunId=row["local_run_id"],
            localDocumentId=row["local_document_id"],
            localDocumentPath=row["local_document_path"],
            completedAt=row["completed_at"],
            createdAt=str(row["created_at"]),
            updatedAt=str(row["updated_at"]),
        )

    def _link_import_request_row_or_404(request_id: str, organization_id: str):
        row = state.db.fetchone(
            """
            SELECT req.*, author.full_name AS requested_by_name
            FROM link_import_requests req
            LEFT JOIN employee_accounts author ON author.id = req.requested_by_user_id
            WHERE req.id = ? AND req.organization_id = ?
            """,
            (request_id, organization_id),
        )
        if row is None:
            raise HTTPException(status_code=404, detail="Link import request not found")
        return row

    @app.get("/api/v1/link-import-requests", response_model=list[LinkImportRequestRecord])
    def list_link_import_requests(
        status_filter: str | None = Query(default=None, alias="status"),
        limit: int = Query(default=100, ge=1, le=200),
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> list[LinkImportRequestRecord]:
        query = [
            """
            SELECT req.*, author.full_name AS requested_by_name
            FROM link_import_requests req
            LEFT JOIN employee_accounts author ON author.id = req.requested_by_user_id
            WHERE req.organization_id = ?
            """
        ]
        params: list[object] = [current_user.organizationId]
        if status_filter:
            query.append("AND req.status = ?")
            params.append(status_filter)
        query.append("ORDER BY req.updated_at DESC LIMIT ?")
        params.append(limit)
        rows = state.db.fetchall(" ".join(query), tuple(params))
        return [_link_import_request_record(row) for row in rows]

    @app.post("/api/v1/link-import-requests", response_model=LinkImportRequestRecord)
    def create_link_import_request(
        payload: LinkImportRequestCreatePayload,
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> LinkImportRequestRecord:
        url = payload.url.strip()
        if not url.lower().startswith(("http://", "https://")):
            raise HTTPException(status_code=422, detail="仅支持 http(s) 链接")
        # 幂等: 同组织同链接已在排队/处理中 → 直接返回既有请求(防重复提交)。
        existing = state.db.fetchone(
            """
            SELECT req.*, author.full_name AS requested_by_name
            FROM link_import_requests req
            LEFT JOIN employee_accounts author ON author.id = req.requested_by_user_id
            WHERE req.organization_id = ? AND req.url = ? AND req.status IN ('pending', 'processing')
            ORDER BY req.created_at DESC
            """,
            (current_user.organizationId, url),
        )
        if existing is not None:
            return _link_import_request_record(existing)
        request_id = new_id("link_import")
        timestamp = now_iso()
        state.db.execute(
            """
            INSERT INTO link_import_requests(
                id, organization_id, url, source_hint, client_id, client_name,
                status, requested_by_user_id, created_at, updated_at
            ) VALUES(?, ?, ?, ?, ?, ?, 'pending', ?, ?, ?)
            """,
            (
                request_id,
                current_user.organizationId,
                url,
                (payload.sourceHint or "").strip() or None,
                (payload.clientId or "").strip() or None,
                (payload.clientName or "").strip() or None,
                current_user.id,
                timestamp,
                timestamp,
            ),
        )
        _log_audit(
            state,
            "link_import.request_created",
            actor_user_id=current_user.id,
            target_user_id=None,
            detail={"requestId": request_id, "url": url, "clientId": payload.clientId or ""},
        )
        row = _link_import_request_row_or_404(request_id, current_user.organizationId)
        return _link_import_request_record(row)

    @app.post("/api/v1/link-import-requests/{request_id}/status", response_model=LinkImportRequestRecord)
    def update_link_import_request(
        request_id: str,
        payload: LinkImportRequestUpdatePayload,
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> LinkImportRequestRecord:
        row = _link_import_request_row_or_404(request_id, current_user.organizationId)
        timestamp = now_iso()
        normalized_error = payload.errorMessage.strip() or None
        completed_at = timestamp if payload.status == "completed" else None
        if payload.status == "processing":
            normalized_error = None
        state.db.execute(
            """
            UPDATE link_import_requests
            SET status = ?, error_message = ?,
                local_run_id = COALESCE(?, local_run_id),
                local_document_id = ?, local_document_path = ?,
                client_id = COALESCE(?, client_id),
                client_name = COALESCE(?, client_name),
                completed_at = ?, updated_at = ?
            WHERE id = ?
            """,
            (
                payload.status,
                normalized_error,
                payload.localRunId,
                payload.localDocumentId,
                payload.localDocumentPath,
                (payload.clientId or "").strip() or None,
                (payload.clientName or "").strip() or None,
                completed_at,
                timestamp,
                request_id,
            ),
        )
        _log_audit(
            state,
            "link_import.request_updated",
            actor_user_id=current_user.id,
            target_user_id=None,
            detail={"requestId": request_id, "status": payload.status, "localRunId": payload.localRunId or ""},
        )
        updated = _link_import_request_row_or_404(request_id, current_user.organizationId)
        return _link_import_request_record(updated)

    # ── Software Feedback (软件内报错/提建议 → 后台收件箱) ───
    # 数据 SSOT: software_feedback 表; 桌面经 cloud_request proxy 上报, admin-v2 控制台读取.

    @app.get("/api/v1/software-feedback", response_model=list[SoftwareFeedbackRecord])
    def list_software_feedback(
        status_filter: str | None = Query(default=None, alias="status"),
        category: str | None = Query(default=None),
        severity: str | None = Query(default=None),
        limit: int = Query(default=50, ge=1, le=200),
        offset: int = Query(default=0, ge=0),
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> list[SoftwareFeedbackRecord]:
        query = ["SELECT * FROM software_feedback WHERE organization_id = ?"]
        params: list[object] = [current_user.organizationId]
        if status_filter:
            query.append("AND status = ?")
            params.append(status_filter)
        if category:
            query.append("AND category = ?")
            params.append(category)
        if severity:
            query.append("AND severity = ?")
            params.append(severity)
        if current_user.primaryRole != "admin":
            query.append("AND reporter_user_id = ?")
            params.append(current_user.id)
        query.append(
            "ORDER BY CASE severity WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'medium' THEN 2 ELSE 3 END,"
            " updated_at DESC LIMIT ? OFFSET ?"
        )
        params.extend([limit, offset])
        rows = state.db.fetchall(" ".join(query), tuple(params))
        return [_software_feedback_record(row) for row in rows]

    @app.post("/api/v1/software-feedback", response_model=SoftwareFeedbackRecord)
    def create_software_feedback(
        payload: SoftwareFeedbackCreatePayload,
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> SoftwareFeedbackRecord:
        if payload.taskId:
            task_row = _task_row_or_404(state, payload.taskId)
            if str(task_row["organization_id"]) != current_user.organizationId:
                raise HTTPException(status_code=404, detail="Task not found")
        feedback_id = new_id("fb")
        timestamp = now_iso()
        state.db.execute(
            """
            INSERT INTO software_feedback (
                id, organization_id, reporter_user_id, reporter_name,
                category, severity, status, title, description,
                app_version, platform, page_route, device_info, log_excerpt, screenshot_path,
                client_id, task_id, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, 'open', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                feedback_id,
                current_user.organizationId,
                current_user.id,
                current_user.fullName,
                payload.category,
                payload.severity,
                payload.title.strip(),
                payload.description.strip(),
                payload.appVersion,
                payload.platform,
                payload.pageRoute,
                payload.deviceInfo,
                payload.logExcerpt,
                payload.screenshotPath,
                payload.clientId,
                payload.taskId,
                timestamp,
                timestamp,
            ),
        )
        _log_audit(
            state,
            "software_feedback.created",
            actor_user_id=current_user.id,
            target_user_id=None,
            detail={"feedbackId": feedback_id, "category": payload.category, "severity": payload.severity},
        )
        return _software_feedback_record(
            _software_feedback_row_or_404(state, feedback_id, current_user.organizationId)
        )

    @app.post("/api/v1/software-feedback/{feedback_id}/status", response_model=SoftwareFeedbackRecord)
    def update_software_feedback(
        feedback_id: str,
        payload: SoftwareFeedbackUpdatePayload,
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> SoftwareFeedbackRecord:
        row = _software_feedback_row_or_404(state, feedback_id, current_user.organizationId)
        is_admin = current_user.primaryRole == "admin"
        is_owner = str(row["reporter_user_id"] or "") == current_user.id
        if not (is_admin or is_owner):
            raise HTTPException(status_code=403, detail="你当前没有处理该反馈的权限")

        new_status = payload.status or str(row["status"])
        if is_admin:
            new_severity = payload.severity or str(row["severity"])
            assignee = payload.assigneeUserId if payload.assigneeUserId is not None else row["assignee_user_id"]
            target_version = payload.targetVersion if payload.targetVersion is not None else row["target_version"]
            resolution_note = payload.resolutionNote if payload.resolutionNote is not None else row["resolution_note"]
        else:
            # 提交人仅能流转自己反馈的状态, 不能指派/定目标版本/改严重度
            new_severity = str(row["severity"])
            assignee = row["assignee_user_id"]
            target_version = row["target_version"]
            resolution_note = row["resolution_note"]

        timestamp = now_iso()
        resolved_at = timestamp if new_status in ("resolved", "wontfix") else None
        state.db.execute(
            """
            UPDATE software_feedback
            SET status = ?, severity = ?, assignee_user_id = ?, target_version = ?,
                resolution_note = ?, resolved_at = ?, updated_at = ?
            WHERE id = ?
            """,
            (new_status, new_severity, assignee, target_version, resolution_note, resolved_at, timestamp, feedback_id),
        )
        _log_audit(
            state,
            "software_feedback.updated",
            actor_user_id=current_user.id,
            target_user_id=None,
            detail={"feedbackId": feedback_id, "status": new_status, "severity": new_severity},
        )
        return _software_feedback_record(
            _software_feedback_row_or_404(state, feedback_id, current_user.organizationId)
        )

    # ── App Installs (客户端身份上报 → 当前版本/安装数 KPI + 定向推送目标) ───

    @app.post("/api/v1/app/checkin", response_model=AppInstallRecord)
    def app_checkin(
        payload: AppCheckinPayload,
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> AppInstallRecord:
        timestamp = now_iso()
        state.db.execute(
            """
            INSERT INTO app_installs (
                install_id, organization_id, user_id, platform, arch, app_version, channel,
                first_seen_at, last_seen_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(install_id) DO UPDATE SET
                organization_id = excluded.organization_id,
                user_id = excluded.user_id,
                platform = excluded.platform,
                arch = excluded.arch,
                app_version = excluded.app_version,
                channel = excluded.channel,
                last_seen_at = excluded.last_seen_at
            """,
            (
                payload.installId,
                current_user.organizationId,
                current_user.id,
                payload.platform,
                payload.arch,
                payload.appVersion,
                payload.channel,
                timestamp,
                timestamp,
            ),
        )
        row = state.db.fetchone("SELECT * FROM app_installs WHERE install_id = ?", (payload.installId,))
        return _app_install_record(row)

    @app.get("/api/v1/app/installs", response_model=list[AppInstallRecord])
    def list_app_installs(
        platform: str | None = Query(default=None),
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_admin(app, authorization)),
    ) -> list[AppInstallRecord]:
        query = ["SELECT * FROM app_installs WHERE organization_id = ?"]
        params: list[object] = [current_user.organizationId]
        if platform:
            query.append("AND platform = ?")
            params.append(platform)
        query.append("ORDER BY last_seen_at DESC")
        rows = state.db.fetchall(" ".join(query), tuple(params))
        return [_app_install_record(row) for row in rows]

    # ── App Releases (发版记录 + 客户端 update-policy 解析) ───
    # v1: 按渠道(internal/beta/stable) 解析最新 published 版本; 逐组织灰度为后续增量.

    @app.get("/api/v1/app/update-policy", response_model=UpdatePolicyResponse)
    def app_update_policy(
        platform: str = Query(...),
        channel: str = Query(default="stable"),
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_auth(app, authorization)),
    ) -> UpdatePolicyResponse:
        rows = state.db.fetchall(
            "SELECT * FROM app_releases WHERE channel = ? AND status = 'published' ORDER BY published_at DESC",
            (channel,),
        )
        for row in rows:
            platforms = json.loads(row["platforms_json"] or "[]")
            if not platforms or platform in platforms:
                return UpdatePolicyResponse(
                    hasUpdate=True,
                    version=str(row["version"]),
                    forceUpdate=bool(row["force_update"]),
                    changelogUser=str(row["changelog_user"] or ""),
                    publishedAt=str(row["published_at"]) if row["published_at"] else None,
                )
        return UpdatePolicyResponse(hasUpdate=False)

    @app.get("/api/v1/app/releases", response_model=list[ReleaseRecord])
    def list_app_releases(
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_admin(app, authorization)),
    ) -> list[ReleaseRecord]:
        rows = state.db.fetchall("SELECT * FROM app_releases ORDER BY created_at DESC")
        return [_release_record(row) for row in rows]

    @app.post("/api/v1/app/releases", response_model=ReleaseRecord)
    def create_app_release(
        payload: ReleaseCreatePayload,
        current_user: SessionUser = Depends(lambda authorization=Header(default=None): _require_admin(app, authorization)),
    ) -> ReleaseRecord:
        release_id = new_id("rel")
